import React, { useRef, useState } from "react";
import "./FileUpload.css";

export default function FileUpload({ onUpload, error }) {
  const inputRef = useRef();
  const [dragging, setDragging] = useState(false);
  const [fileName, setFileName] = useState(null);

  const process = (file) => {
    if (!file) return;
    setFileName(file.name);
    onUpload(file);
  };

  const onDrop = (e) => {
    e.preventDefault();
    setDragging(false);
    process(e.dataTransfer.files[0]);
  };

  return (
    <div className="upload-page">
      {/* ── Hero text ── */}
      <div className="hero">
        <h1 className="hero-title">
          Understand your<br />
          <span className="hero-highlight">customers</span>
        </h1>
        <p className="hero-body">
          Upload your retail transaction dataset and we'll automatically segment
          your customers using RFM analysis and K-Means clustering.
        </p>
        <div className="hero-tags">
          {["Recency", "Frequency", "Monetary"].map((t) => (
            <span key={t} className="tag">{t}</span>
          ))}
          <span className="tag tag-muted">Auto k-selection</span>
          <span className="tag tag-muted">Large dataset ready</span>
        </div>
      </div>

      {/* ── Drop zone ── */}
      <div
        className={`drop-zone ${dragging ? "dragging" : ""} ${error ? "has-error" : ""}`}
        onDragOver={(e) => { e.preventDefault(); setDragging(true); }}
        onDragLeave={() => setDragging(false)}
        onDrop={onDrop}
        onClick={() => inputRef.current.click()}
      >
        <input
          ref={inputRef}
          type="file"
          accept=".csv,.xlsx,.xls"
          style={{ display: "none" }}
          onChange={(e) => process(e.target.files[0])}
        />
        <div className="drop-icon">
          {dragging ? "⬇" : "◎"}
        </div>
        <p className="drop-main">
          {fileName ? fileName : "Drop your file here"}
        </p>
        <p className="drop-sub">CSV or Excel · any size</p>

        <div className="drop-formats">
          {["CSV", "XLSX", "XLS"].map((f) => (
            <span key={f} className="format-badge">.{f.toLowerCase()}</span>
          ))}
        </div>
      </div>

      {error && (
        <div className="upload-error">
          <span className="error-icon">⚠</span>
          <span>{error}</span>
        </div>
      )}

      {/* ── Expected columns note ── */}
      <div className="cols-hint">
        <p className="cols-hint-title">Auto-detected columns</p>
        <div className="cols-grid">
          <ColHint label="Customer ID" examples="CustomerID, Customer_ID, UserID" />
          <ColHint label="Date" examples="Date, InvoiceDate, Transaction_Date" />
          <ColHint label="Amount" examples="Total_Amount, UnitPrice × Quantity" />
          <ColHint label="Invoice (optional)" examples="InvoiceNo, Transaction_ID, OrderID" />
        </div>
      </div>
    </div>
  );
}

function ColHint({ label, examples }) {
  return (
    <div className="col-hint">
      <span className="col-hint-label">{label}</span>
      <span className="col-hint-examples">{examples}</span>
    </div>
  );
}
